import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { TaxiOpenListParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/roleplay/TaxiOpenListParser';

/**
 * Triggered when the server sends TaxiOpenListComposer
 */
export class TaxiOpenListEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, TaxiOpenListParser);
        console.log('[🚖] TaxiOpenListEvent initialized');
    }

    public getParser(): TaxiOpenListParser {
        return this.parser as TaxiOpenListParser;
    }
}
